/**
 * @summary List all contracts for user
 */
export const getListContractsUrl = (params?: ListContractsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/contracts?${stringifiedParams}`
    : `/api/contracts`;
};

export const listContracts = async (
  params?: ListContractsParams,
  options?: RequestInit,
): Promise<ContractWithExtraction[]> => {
  return customFetch<ContractWithExtraction[]>(getListContractsUrl(params), {
    ...options,
    method: "GET",
  });
};

