/**
 * @summary Upload contract PDF and trigger AI extraction
 */
export const getUploadContractUrl = () => {
  return `/api/contracts/upload`;
};

export const uploadContract = async (
  uploadContractBody: UploadContractBody,
  options?: RequestInit,
): Promise<Contract> => {
  const formData = new FormData();
  formData.append(`file`, uploadContractBody.file);
  if (uploadContractBody.title !== undefined) {
    formData.append(`title`, uploadContractBody.title);
  }

  return customFetch<Contract>(getUploadContractUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

